from typing import Any, Dict, Optional

import boto3
from botocore.exceptions import BotoCoreError, ClientError


EMAIL_RE = re.compile(r"[^@]+@[^@]+\.[^@]+")
PHONE_RE = re.compile(r"^\+?[0-9().\-\s]{7,20}$")


class SQSPublisherError(Exception):
    pass


class ValidationError(SQSPublisherError):
    pass


class SQSPublisher:
    def __init__(
        self,
        queue_url: str,
        region_name: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        aws_session_token: Optional[str] = None,
    ) -> None:
        if not queue_url:
            raise ValueError("queue_url is required")

        session = boto3.session.Session()
        self.sqs = session.client(
            "sqs",
            region_name=region_name or os.getenv("AWS_REGION") or os.getenv("AWS_DEFAULT_REGION"),
            aws_access_key_id=aws_access_key_id or os.getenv("AWS_ACCESS_KEY_ID"),
            aws_secret_access_key=aws_secret_access_key or os.getenv("AWS_SECRET_ACCESS_KEY"),
            aws_session_token=aws_session_token or os.getenv("AWS_SESSION_TOKEN"),
        )
        self.queue_url = queue_url

    def publish_user_data(
        self,
        user_id: str,
        email: str,
        phone_number: str,
        address: Dict[str, Any],
        attributes: Optional[Dict[str, Any]] = None,
        message_group_id: Optional[str] = None,
        deduplication_id: Optional[str] = None,
    ) -> Dict[str, Any]:
        payload = self._build_payload(
            user_id=user_id,
            email=email,
            phone_number=phone_number,
            address=address,
            attributes=attributes or {},
        )

        params: Dict[str, Any] = {
            "QueueUrl": self.queue_url,
            "MessageBody": json.dumps(payload, separators=(",", ":"), ensure_ascii=False),
            "MessageAttributes": {
                "contains_pii": {"DataType": "String", "StringValue": "true"},
                "schema_type": {"DataType": "String", "StringValue": "user_data"},
                "user_id": {"DataType": "String", "StringValue": user_id},
            },
        }

        if self.queue_url.endswith(".fifo"):
            params["MessageGroupId"] = message_group_id or "user-data"
            params["MessageDeduplicationId"] = deduplication_id or str(uuid.uuid4())

        try:
            response = self.sqs.send_message(**params)
            return {
                "message_id": response.get("MessageId"),
                "md5_of_body": response.get("MD5OfMessageBody"),
                "sequence_number": response.get("SequenceNumber"),
            }
        except (ClientError, BotoCoreError) as exc:
            raise SQSPublisherError(f"failed to publish message: {exc}") from exc

    def _build_payload(
        self,
        user_id: str,
        email: str,
        phone_number: str,
        address: Dict[str, Any],
        attributes: Dict[str, Any],
    ) -> Dict[str, Any]:
        self._validate_user_id(user_id)
        self._validate_email(email)
        self._validate_phone(phone_number)
        self._validate_address(address)

        return {
            "event_id": str(uuid.uuid4()),
            "event_type": "USER_PII_DATA",
            "user": {
                "user_id": user_id,
                "email": email,
                "phone_number": phone_number,
                "address": {
                    "line1": address["line1"],
                    "line2": address.get("line2"),
                    "city": address["city"],
                    "state": address["state"],
                    "postal_code": address["postal_code"],
                    "country": address["country"],
                },
            },
            "attributes": attributes,
        }

    @staticmethod
    def _validate_user_id(user_id: str) -> None:
        if not isinstance(user_id, str) or not user_id.strip():
            raise ValidationError("user_id must be a non-empty string")

    @staticmethod
    def _validate_email(email: str) -> None:
        if not isinstance(email, str) or not EMAIL_RE.match(email):
            raise ValidationError("invalid email")

    @staticmethod
    def _validate_phone(phone_number: str) -> None:
        if not isinstance(phone_number, str) or not PHONE_RE.match(phone_number):
            raise ValidationError("invalid phone_number")

    @staticmethod
    def _validate_address(address: Dict[str, Any]) -> None:
        if not isinstance(address, dict):
            raise ValidationError("address must be a dict")

        required_fields = ["line1", "city", "state", "postal_code", "country"]
        missing = [field for field in required_fields if not address.get(field)]
        if missing:
            raise ValidationError(f"missing address fields: {', '.join(missing)}")


